public sealed class FloorBlueprintV3
{
    internal FloorBlueprintV3(string id,string company,GlobalCellCoord cell,string type,FloorDefinitionV3 definition,DateTime created){BlueprintId=id;CompanyId=company;Cell=cell;FloorTypeId=type;MaterialBuffer=new(new[]{new StructureMaterialRequirementV3(definition.ResourceType,definition.ResourceCost)});CreatedUtc=created.ToUniversalTime();}
    public string BlueprintId{get;}public string CompanyId{get;}public GlobalCellCoord Cell{get;}public string FloorTypeId{get;}public ConstructionMaterialBufferV3 MaterialBuffer{get;}public ConstructionBlueprintStatusV3 Status{get;private set;}=ConstructionBlueprintStatusV3.AwaitingMaterials;public float ProgressSeconds{get;private set;}public int Revision{get;private set;}public DateTime CreatedUtc{get;}
    public void RefreshMaterialStatus(){if(Status is ConstructionBlueprintStatusV3.Completed or ConstructionBlueprintStatusV3.Cancelled)return;Status=MaterialBuffer.IsComplete?ConstructionBlueprintStatusV3.ReadyToBuild:ConstructionBlueprintStatusV3.AwaitingMaterials;Revision++;}
    public bool TryBegin(out string reason){if(!MaterialBuffer.IsComplete){reason="MaterialsMissing";return false;}if(Status is ConstructionBlueprintStatusV3.Completed or ConstructionBlueprintStatusV3.Cancelled){reason="InvalidBlueprintState";return false;}Status=ConstructionBlueprintStatusV3.UnderConstruction;Revision++;reason="";return true;}
    public void AddProgress(float delta){if(Status==ConstructionBlueprintStatusV3.UnderConstruction&&delta>0){ProgressSeconds+=delta;Revision++;}}
    internal void MarkCompleted(){Status=ConstructionBlueprintStatusV3.Completed;Revision++;}internal void MarkCancelled(){Status=ConstructionBlueprintStatusV3.Cancelled;Revision++;}
}
public enum FloorDemolitionStatusV3 { Designated, UnderDemolition, Completed, Cancelled }
public sealed class FloorDemolitionMarkV3
{
    internal FloorDemolitionMarkV3(string id,string company,GlobalCellCoord cell,int floorRevision){MarkId=id;CompanyId=company;Cell=cell;FloorRevision=floorRevision;Revision=1;}
    public string MarkId{get;}public string CompanyId{get;}public GlobalCellCoord Cell{get;}public int FloorRevision{get;}public int Revision{get;private set;}public float ProgressSeconds{get;private set;}public FloorDemolitionStatusV3 Status{get;private set;}=FloorDemolitionStatusV3.Designated;
    public bool TryBegin(){if(Status is FloorDemolitionStatusV3.Completed or FloorDemolitionStatusV3.Cancelled)return false;Status=FloorDemolitionStatusV3.UnderDemolition;Revision++;return true;}public bool TryAddProgress(float value){if(Status!=FloorDemolitionStatusV3.UnderDemolition||value<0||!float.IsFinite(value))return false;ProgressSeconds+=value;Revision++;return true;}public void Reset(){if(Status!=FloorDemolitionStatusV3.Completed){Status=FloorDemolitionStatusV3.Designated;Revision++;}}internal void Complete(){Status=FloorDemolitionStatusV3.Completed;Revision++;}
}
public sealed class FloorChunkDataV3
{
    private readonly HashSet<Vector2I> _floorCells=new(),_blueprintCells=new(),_markCells=new();internal FloorChunkDataV3(Vector2I coord)=>ChunkCoord=coord;
    public Vector2I ChunkCoord{get;}public long Revision{get;internal set;}public long VisualRevision{get;internal set;}public long MovementCostRevision{get;internal set;}public int FloorCount=>_floorCells.Count;public int BlueprintCount=>_blueprintCells.Count;public int MarkCount=>_markCells.Count;public bool IsEmpty=>FloorCount+BlueprintCount+MarkCount==0;
    internal void AddFloor(Vector2I c){_floorCells.Add(c);Touch(true);}internal void RemoveFloor(Vector2I c){_floorCells.Remove(c);Touch(true);}internal void AddBlueprint(Vector2I c){_blueprintCells.Add(c);Touch(false);}internal void RemoveBlueprint(Vector2I c){_blueprintCells.Remove(c);Touch(false);}internal void AddMark(Vector2I c){_markCells.Add(c);Touch(false);}internal void RemoveMark(Vector2I c){_markCells.Remove(c);Touch(false);}private void Touch(bool movement){Revision++;VisualRevision++;if(movement)MovementCostRevision++;}
    public IReadOnlyCollection<Vector2I> FloorCells=>_floorCells;public IReadOnlyCollection<Vector2I> BlueprintCells=>_blueprintCells;public IReadOnlyCollection<Vector2I> MarkCells=>_markCells;
}
